/* ─── Canvas Globe ─── */
const gs=[{country:"United Kingdom",flag:"\u{1F1EC}\u{1F1E7}",name:"Sarah, 34, Leeds",quote:"I called at 8:01am. Busy. By 8:15 all slots were gone. Three weeks of this.",laura:"Laura prepares a structured callback request so the practice can respond more efficiently.",lat:54,lng:-1.5},{country:"United States",flag:"\u{1F1FA}\u{1F1F8}",name:"Marcus, 28, Chicago",quote:"I delayed seeing a doctor for six months because I was terrified of the cost.",laura:"Laura surfaces lower-cost options and community clinics near you automatically.",lat:41.8,lng:-87.6},{country:"Nigeria",flag:"\u{1F1F3}\u{1F1EC}",name:"Amina, 41, Lagos",quote:"Four doctors for ten thousand people. I spent two days trying to find someone.",laura:"Laura searches provider availability in real time and helps route you to whoever can see you soonest.",lat:6.5,lng:3.4},{country:"India",flag:"\u{1F1EE}\u{1F1F3}",name:"Priya, 55, Jaipur",quote:"My mother lives two hours from the nearest clinic. She never knows when to worry.",laura:"Laura helps assess urgency remotely and tells you whether to travel now or monitor at home.",lat:26.9,lng:75.8},{country:"Brazil",flag:"\u{1F1E7}\u{1F1F7}",name:"Lucas, 23, London",quote:"I moved to London and could not explain my symptoms in English.",laura:"Laura captures symptoms in your language, generates a structured bilingual note, and helps you share it before you arrive.",lat:51.5,lng:-0.1}];

function latLngToXYZ(lat:number,lng:number){const phi=(90-lat)*(Math.PI/180);const theta=(lng+180)*(Math.PI/180);return{x:-Math.sin(phi)*Math.cos(theta),y:Math.cos(phi),z:Math.sin(phi)*Math.sin(theta)};}

function CanvasGlobe({active}:{active:number}){
  const canvasRef=useRef<HTMLCanvasElement>(null);const rotRef=useRef(0.4);const frameRef=useRef(0);
  useEffect(()=>{
    const canvas=canvasRef.current;if(!canvas)return;const ctx=canvas.getContext("2d");if(!ctx)return;
    const dpr=window.devicePixelRatio||1;
    function resize(){if(!canvas)return;const rect=canvas.getBoundingClientRect();canvas.width=rect.width*dpr;canvas.height=rect.height*dpr;}
    resize();
    const N=300;const golden=Math.PI*(3-Math.sqrt(5));const dots:{x:number;y:number;z:number}[]=[];
    for(let i=0;i<N;i++){const theta=golden*i;const phi=Math.acos(1-2*(i+0.5)/N);dots.push({x:Math.cos(theta)*Math.sin(phi),y:Math.cos(phi),z:Math.sin(theta)*Math.sin(phi)});}
    const cityXYZ=gs.map(g=>latLngToXYZ(g.lat,g.lng));
    function draw(){
      if(!canvas||!ctx)return;
      const w=canvas.width/dpr;const h=canvas.height/dpr;const R=Math.min(w,h)*0.42;const cx=w/2;const cy=h/2;
      const rot=rotRef.current;const cosR=Math.cos(rot);const sinR=Math.sin(rot);
      ctx.setTransform(dpr,0,0,dpr,0,0);ctx.clearRect(0,0,w,h);
      // Glow
      const glow=ctx.createRadialGradient(cx-R*0.2,cy-R*0.2,0,cx,cy,R*1.3);
      glow.addColorStop(0,"rgba(201,149,107,0.07)");glow.addColorStop(0.6,"rgba(201,149,107,0.02)");glow.addColorStop(1,"transparent");
      ctx.fillStyle=glow;ctx.fillRect(0,0,w,h);
      // Outline
      ctx.beginPath();ctx.arc(cx,cy,R,0,Math.PI*2);ctx.strokeStyle="rgba(192,184,164,0.25)";ctx.lineWidth=0.8;ctx.stroke();
      // Inner fill
      const sg=ctx.createRadialGradient(cx-R*0.25,cy-R*0.25,R*0.1,cx,cy,R);
      sg.addColorStop(0,"rgba(248,246,241,0.06)");sg.addColorStop(1,"rgba(224,218,200,0.03)");
      ctx.fillStyle=sg;ctx.beginPath();ctx.arc(cx,cy,R,0,Math.PI*2);ctx.fill();
      // Grid
      ctx.strokeStyle="rgba(200,192,172,0.07)";ctx.lineWidth=0.5;
      for(let lat=-60;lat<=60;lat+=30){const p=(90-lat)*Math.PI/180;const rr=Math.sin(p)*R;const ry=cy-Math.cos(p)*R;ctx.beginPath();ctx.ellipse(cx,ry,rr,rr*0.12,0,0,Math.PI*2);ctx.stroke();}
      // Dots
      for(const p of dots){const x=p.x*cosR+p.z*sinR;const z=-p.x*sinR+p.z*cosR;const y=p.y;if(z<-0.05)continue;const sx=cx+x*R;const sy=cy-y*R;const alpha=Math.max(0,Math.min(1,(z+0.3)*0.6));const sz=1+z*0.8;ctx.beginPath();ctx.arc(sx,sy,sz,0,Math.PI*2);ctx.fillStyle=`rgba(180,168,148,${alpha*0.55})`;ctx.fill();}
      // Cities
      const projected:{sx:number;sy:number;z:number}[]=[];
      for(let i=0;i<cityXYZ.length;i++){const p=cityXYZ[i];const x=p.x*cosR+p.z*sinR;const z=-p.x*sinR+p.z*cosR;const y=p.y;const sx=cx+x*R;const sy=cy-y*R;projected.push({sx,sy,z});if(z<0)continue;
        if(i===active){ctx.beginPath();ctx.arc(sx,sy,8,0,Math.PI*2);ctx.fillStyle="rgba(201,149,107,0.15)";ctx.fill();ctx.beginPath();ctx.arc(sx,sy,14,0,Math.PI*2);ctx.fillStyle="rgba(201,149,107,0.06)";ctx.fill();}
        ctx.beginPath();ctx.arc(sx,sy,i===active?4:2.5,0,Math.PI*2);ctx.fillStyle=i===active?c.warm:"rgba(176,168,148,0.7)";ctx.fill();}
      // Arcs
      for(let i=0;i<cityXYZ.length;i++){const next=(i+1)%cityXYZ.length;const a=projected[i];const b=projected[next];if(a.z<-0.2||b.z<-0.2)continue;const mx=(a.sx+b.sx)/2;const my=(a.sy+b.sy)/2-Math.abs(a.sx-b.sx)*0.2;ctx.beginPath();ctx.moveTo(a.sx,a.sy);ctx.quadraticCurveTo(mx,my,b.sx,b.sy);ctx.strokeStyle=i===active?"rgba(201,149,107,0.35)":"rgba(201,149,107,0.06)";ctx.lineWidth=i===active?1.2:0.5;ctx.setLineDash(i===active?[4,3]:[]);ctx.stroke();ctx.setLineDash([]);}
      rotRef.current+=0.002;frameRef.current=requestAnimationFrame(draw);
    }
    frameRef.current=requestAnimationFrame(draw);
    const ro=new ResizeObserver(()=>{resize();});ro.observe(canvas);
    return()=>{cancelAnimationFrame(frameRef.current);ro.disconnect();};
  },[active]);
  return<canvas ref={canvasRef} className="globeCanvas"/>;
}

function GlobeSection(){const[a,setA]=useState(0);const tr=useRef<ReturnType<typeof setTimeout>|null>(null);const reset=useCallback(()=>{if(tr.current)clearTimeout(tr.current);tr.current=setTimeout(()=>setA(p=>(p+1)%gs.length),6000);},[]);useEffect(()=>{reset();return()=>{if(tr.current)clearTimeout(tr.current);};},[a,reset]);const s=gs[a];return(
<section className="globeSec"><div className="container"><FI><div className="shW"><h2 className="serif shT">How people struggle to reach care.</h2></div></FI><div className="globeW"><div className="globeV"><CanvasGlobe active={a}/></div><div className="globeC"><AnimatePresence mode="wait"><motion.div key={a} initial={{opacity:0,y:10}} animate={{opacity:1,y:0}} exit={{opacity:0,y:-6}} transition={{duration:0.3}} className="globeStory"><div className="globeCtry"><span style={{fontSize:"18px"}}>{s.flag}</span><span className="globeCtryN">{s.country}</span></div><p className="serif globeQ">&ldquo;{s.quote}&rdquo;</p><p className="globeNm">{s.name}</p><div className="globeL"><div className="globeLA"><Image src="/laura-avatar.png" alt="Laura" fill sizes="22px" style={{objectFit:"cover"}}/></div><p className="globeLT">{s.laura}</p></div></motion.div></AnimatePresence><div className="globeNav"><div className="globeDs">{gs.map((_,i)=><button key={i} className={`globeD${i===a?" globeDA":""}`} onClick={()=>setA(i)}/>)}</div><div className="globeAs"><button className="globeA" onClick={()=>setA(p=>(p-1+5)%5)}><ChevronLeft size={15}/></button><button className="globeA" onClick={()=>setA(p=>(p+1)%5)}><ChevronRight size={15}/></button></div></div></div></div></div></section>);}

