function RoadmapCards(){return(<section className="sec"><div className="container"><FI><div className="shW"><h2 className="serif shT">Where Laura is going.</h2><p className="shB">We are starting with care navigation first. Here is what comes next.</p></div></FI><div className="roadScroll">{roadmapItems.map((item,i)=>(<motion.div key={item.title} className="roadCard" initial={{opacity:0,y:14}} whileInView={{opacity:1,y:0}} viewport={{once:true}} transition={{delay:i*0.08}}><div className="roadTop"><motion.span className="roadEmoji" animate={{y:[0,-3,0],rotate:[0,5,-5,0]}} transition={{duration:3+i*0.3,repeat:Infinity,ease:"easeInOut"}}>{item.emoji}</motion.span><motion.span className="roadSt" animate={{scale:[1,1.05,1]}} transition={{duration:2,repeat:Infinity,delay:i*0.4}}>{item.stage}</motion.span></div><h4 className="roadTi">{item.title}</h4><p className="roadDs">{item.desc}</p><div className="roadLine"/></motion.div>))}</div><FI delay={0.3}><p className="roadNote">Laura currently works through the website. WhatsApp and other access channels are part of the roadmap.</p></FI></div></section>);}

