/* ─── Modal ─── */
function SuccessModal({open,onClose,referralCode}:{open:boolean;onClose:()=>void;referralCode:string}){
  const[copied,setCopied]=useState(false);const link=typeof window!=="undefined"?`${window.location.origin}?ref=${referralCode}`:"";
  function copyLink(){navigator.clipboard.writeText(link).then(()=>{setCopied(true);setTimeout(()=>setCopied(false),2000);});}
  async function shareLink(){if(navigator.share){try{await navigator.share({title:"Join Omela",text:"Skip the GP queue. Laura helps you navigate healthcare.",url:link});}catch{}}else{copyLink();}}
  return<AnimatePresence>{open&&<motion.div initial={{opacity:0}} animate={{opacity:1}} exit={{opacity:0}} onClick={onClose} className="modO"><motion.div initial={{opacity:0,y:20,scale:0.95}} animate={{opacity:1,y:0,scale:1}} exit={{opacity:0,y:10}} transition={{type:"spring",damping:20,stiffness:300}} onClick={e=>e.stopPropagation()} className="modB"><Confetti/><motion.div className="modCel" initial={{scale:0}} animate={{scale:1}} transition={{type:"spring",delay:0.2,stiffness:400,damping:15}}><span className="modCelE">{"\u{1F389}"}</span></motion.div><h3 className="serif modTi">You are on the list!</h3><p className="modBd">Laura will reach out as access opens. Invite 3 friends to move up the waitlist and unlock bonus credits.</p>{referralCode&&<div className="modRef"><p className="modRefLbl">Your referral link</p><div className="modRefBox"><span className="modRefUrl">{link.replace("https://","").replace("http://","")}</span><button onClick={copyLink} className="modRefCp" type="button">{copied?<Check size={14}/>:<Copy size={14}/>}</button></div><div className="modRefBts"><button onClick={shareLink} className="btnP modShareBtn" type="button"><Share2 size={13}/>Share link</button><a href="https://x.com/joinomela" target="_blank" rel="noreferrer" className="btnS modXBtn">Follow @joinomela</a></div></div>}<button type="button" className="modClose" onClick={onClose}>Close</button></motion.div></motion.div>}</AnimatePresence>;}

