export default function Page(){
  const[role,setRole]=useState<Role>("patient");const[email,setEmail]=useState("");const[website,setWebsite]=useState("");const[agreed,setAgreed]=useState(false);const[submitting,setSubmitting]=useState(false);const[success,setSuccess]=useState("");const[error,setError]=useState("");const[modalOpen,setModalOpen]=useState(false);const[referralCode,setReferralCode]=useState("");const[refParam,setRefParam]=useState("");
  useEffect(()=>{if(typeof window!=="undefined"){const params=new URLSearchParams(window.location.search);const ref=params.get("ref");if(ref)setRefParam(ref);}},[]);
  async function handleSubmit(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!agreed)return;setSubmitting(true);setSuccess("");setError("");try{const res=await fetch("/api/waitlist",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email,role,website,source:"landing-page",marketingOptIn:false,ref:refParam||undefined})});const data=await res.json();if(!res.ok){if(data.referralCode)setReferralCode(data.referralCode);setError(data.error||"Something went wrong.");return;}setSuccess(data.message||"You are in.");if(data.referralCode)setReferralCode(data.referralCode);setEmail("");setRole("patient");setWebsite("");setAgreed(false);setModalOpen(true);}catch{setError("Something went wrong.");}finally{setSubmitting(false);}}

  return(<><style>{FONT}</style><style>{CSS}</style>
    <SuccessModal open={modalOpen} onClose={()=>setModalOpen(false)} referralCode={referralCode}/>
    <div className="wrap">
      <StatusBar/>
      <motion.nav initial={{opacity:0,y:-8}} animate={{opacity:1,y:0}} className="nav"><div className="container navR"><Link href="/" className="navBr"><div className="navLo"><Image src="/omela-logo-mark.png" alt="Omela" width={34} height={34} style={{width:"100%",height:"100%",objectFit:"contain"}}/></div><div><div className="navNm">Omela</div><div className="navSb">POWERED BY LAURA</div></div></Link><div className="navLks"><a href="#how" className="navLk">How it works</a><a href="#pricing" className="navLk">Pricing</a><Link href="/how-laura-helps" className="navLk">Use cases</Link></div><a href="#waitlist" className="btnP navCt">Join waitlist <ArrowRight size={13}/></a></div></motion.nav>

      <section className="heroSec"><div className="container"><div className="heroTxt"><FI><h1 className="serif heroTi">Getting care<br/><span className="heroAc">should not be this hard.</span></h1></FI><FI delay={0.05}><div className="heroBd"><Typewriter/></div></FI><FI delay={0.1}><p className="heroSub">Laura is a care navigation platform that helps people find doctors, prepare prescription requests, understand referral letters, and generate bilingual notes for the practice. She does not just answer questions. She helps move care access forward.</p></FI><FI delay={0.14}><div className="heroBt"><Link href="/demo" className="btnP">See Laura in action <ArrowRight size={14}/></Link><a href="#waitlist" className="btnS">Join waitlist</a></div></FI></div><div className="heroPh"><PhoneMockup/></div></div></section>

      <section id="how" className="sec"><div className="container"><FI><div className="shW"><h2 className="serif shT">Laura does not just answer health questions.<br/>She helps get the admin moving.</h2></div></FI><div className="capGrid">{[{icon:<Search size={22}/>,title:"Finds doctors and helps prepare requests",body:"Laura searches practices near you, surfaces suitable options, and helps prepare registration or callback requests for submission with your approval."},{icon:<FileCheck size={22}/>,title:"Drafts prescriptions and tracks refills",body:"Laura prepares your repeat prescription request, helps you send it through the available channel, and reminds you before you run out."},{icon:<Languages size={22}/>,title:"Generates structured bilingual notes",body:"Laura captures your symptoms in your language and turns them into a structured bilingual note you can share with the practice."}].map((item,i)=>(<FI key={item.title} delay={i*0.07}><div className="capCard"><motion.div className="capIc" animate={{y:[0,-4,0]}} transition={{duration:3+i*0.5,repeat:Infinity,ease:"easeInOut"}}>{item.icon}</motion.div><h3 className="capTi">{item.title}</h3><p className="capBd">{item.body}</p></div></FI>))}</div><FI delay={0.2}><div style={{textAlign:"center",marginTop:"28px"}}><Link href="/how-laura-helps" className="seeAll">See all care scenarios <ArrowRight size={14}/></Link></div></FI></div></section>

      <section className="sec" style={{paddingTop:0}}><div className="container"><FI><div className="shW"><h2 className="serif shT">A chatbot answers questions.<br/>Laura helps move care access forward.</h2></div></FI><FI><div className="baGrid"><div className="baCard baBf"><h3 className="baTi">Without Laura</h3>{["You call the GP. Busy signal. Try again tomorrow.","You email the pharmacy. No reply for three days.","You get a referral full of medical jargon with no guidance.","You arrive in a new city with zero medical contacts.","You try to explain symptoms in a language that is not yours."].map(item=><div key={item} className="baIt"><span className="baX">&#10007;</span>{item}</div>)}</div><div className="baCard baAf"><h3 className="baTi">With Laura</h3>{["Laura prepares a structured callback request and helps route it through the available channel.","Laura drafts your refill request and helps submit it where supported.","Laura translates your referral into plain language with appointment prep.","Laura finds nearby accepting practices and helps prepare the registration request.","Laura prepares a bilingual note for the practice that you can review and share."].map(item=><div key={item} className="baIt"><Chk/><span>{item}</span></div>)}</div></div></FI></div></section>

      <GlobeSection/>

      <section className="sec"><div className="container"><FI><div className="shW"><h2 className="serif shT">Who Laura is for.</h2></div></FI><div className="audGrid">{[{icon:<Users size={22}/>,title:"People",desc:"Laura helps act on your behalf. She finds nearby practices, drafts your prescription request, explains your hospital letter, and helps prepare your callback request. You spend less time chasing the system.",color:c.accent},{icon:<Building2 size={22}/>,title:"Care teams",desc:"Laura intercepts and structures incoming patient demand before it hits reception. She helps assess urgency, captures symptoms in structured format, and helps route the next step.",color:c.green},{icon:<Code2 size={22}/>,title:"Developers",desc:"Embed Laura's care-navigation engine into your product via API. Provider search, urgency assessment, prescription routing, and multilingual intake.",color:c.warm,soon:true}].map((item,i)=>(<FI key={item.title} delay={i*0.07}><div className="audCard"><motion.div className="audIc" style={{background:`${item.color}10`,color:item.color}} animate={{rotate:[0,3,-3,0]}} transition={{duration:4+i,repeat:Infinity,ease:"easeInOut"}}>{item.icon}</motion.div><div style={{display:"flex",alignItems:"center",gap:"6px"}}><h3 className="audTi">{item.title}</h3>{item.soon&&<Soon/>}</div><p className="audBd">{item.desc}</p></div></FI>))}</div></div></section>

      <section className="sec" style={{paddingTop:0}}><div className="container"><FI><div className="glC"><div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:"8px",flexWrap:"wrap"}}><h2 className="serif glT">Laura speaks your language.</h2><Soon/></div><p className="glB">40+ languages. Laura responds in the language you start with and generates structured bilingual notes for the practice.</p><div className="glF">{["\u{1F1EC}\u{1F1E7} UK","\u{1F1FA}\u{1F1F8} US","\u{1F1EB}\u{1F1F7} France","\u{1F1F3}\u{1F1EC} Nigeria","\u{1F1EE}\u{1F1F3} India","\u{1F30D} 40+ more"].map(f=><span key={f} className="glFi">{f}</span>)}</div></div></FI></div></section>

      <section className="secDk"><div className="container"><FI><div className="shW"><h2 className="serif shT" style={{color:"#fff"}}>Build with Laura.</h2><p className="shB" style={{color:"rgba(255,255,255,0.5)"}}>Embed care navigation, provider routing, and multilingual intake into your product.</p></div></FI><div className="g2" style={{marginTop:"32px"}}><FI><SDKTerminal/></FI><FI delay={0.08}><div className="dkC"><h3 className="dkCT">Infrastructure for health apps</h3><p className="dkCB">Add Laura to patient portals, telehealth platforms, or internal tooling.</p><div className="ftL" style={{marginTop:"16px"}}>{["Provider search and availability API","Urgency assessment engine","Prescription and callback routing","Multilingual intake with bilingual notes"].map(f=><div key={f} className="ftR" style={{color:"rgba(255,255,255,0.7)"}}><Chk dark/><span>{f}</span></div>)}</div></div></FI></div></div></section>

      <RoadmapCards/>
      <InfraSection/>

      <section id="pricing" className="secPr"><div className="container"><FI><div className="shW"><h2 className="serif shT">Credits-based pricing.</h2><p className="shB">Every action Laura takes uses credits. Start free. Pay as you grow.</p></div></FI><div className="prGrid">{[{name:"People",price:"50 free credits",period:"then \u00a34.99 / 200 credits",desc:"For individuals navigating the healthcare system.",features:["Find nearby GP practices","Prepare callback requests","Draft repeat prescriptions","Explain referral letters","Urgency guidance","Bilingual note generation"],cta:"Join waitlist",hl:false},{name:"Care Teams",price:"From \u00a32,500",period:"/month",desc:"For GP practices, clinics, and care organisations managing patient demand at scale.",features:["Structured patient intake","Urgency assessment and routing","Multilingual access for patients","Callback and request management","Demand analytics dashboard","Dedicated onboarding support"],cta:"Request demo",hl:true,badge:"Best for practices"},{name:"Developer",price:"Custom",period:"usage-based",desc:"For health platforms, patient portals, and telehealth apps embedding Laura's engine via API.",features:["Full REST API access","Provider search endpoints","Urgency assessment engine","Prescription routing API","Multilingual intake pipeline","Sandbox environment","Priority engineering support"],cta:"Talk to us",hl:false,soon:true}].map((p,i)=>(<FI key={p.name} delay={i*0.06}><div className={`prCard${p.hl?" prCardDk":""}`}>{p.badge&&<div className="prBg">{p.badge}</div>}<div style={{display:"flex",alignItems:"center",gap:"6px"}}><span className="prNm">{p.name}</span>{p.soon&&<Soon/>}</div><div className="prPr"><span className="serif prAmt">{p.price}</span></div><p className="prPd2">{p.period}</p><p className="prDs">{p.desc}</p><div className="prFts">{p.features.map(f=><div key={f} className="prFt"><Chk dark={p.hl}/><span>{f}</span></div>)}</div><a href="#waitlist" className={`btnP prBt${p.hl?" prBtW":""}`}>{p.cta}</a></div></FI>))}</div></div></section>

      <section id="waitlist" className="sec"><div className="container"><FI><div className="wlC"><div className="shW"><h2 className="serif shT">Join the waitlist.</h2><p className="shB">We are onboarding in batches. Early members receive 50 free credits.</p></div><form className="wlF" onSubmit={handleSubmit}><input className="inp" type="email" placeholder="Your email" value={email} onChange={e=>setEmail(e.target.value)} required autoComplete="email"/><select className="inp" value={role} onChange={e=>setRole(e.target.value as Role)}><option value="patient">I need care access</option><option value="provider">I run a practice</option><option value="developer">I am a developer</option></select><input type="text" name="website" value={website} onChange={e=>setWebsite(e.target.value)} tabIndex={-1} autoComplete="off" aria-hidden="true" style={{position:"absolute",left:"-9999px",opacity:0,pointerEvents:"none",height:0,width:0}}/><button type="submit" className="btnP wlBt" disabled={submitting||!agreed}>{submitting?"Submitting...":"Join waitlist"}</button></form><label className="pvL"><input type="checkbox" checked={agreed} onChange={e=>setAgreed(e.target.checked)} required className="pvC"/><span>I agree to the <Link href="/privacy" className="pvLk">Privacy Notice</Link> and <Link href="/terms" className="pvLk">Terms</Link>.</span></label><div className="wlBadges"><span className="wlBadge"><Shield size={11}/>Privacy-first by design</span><span className="wlBadge"><Shield size={11}/>Built with UK data protection in mind</span></div>{success&&<div className="fmOk">{success}</div>}{error&&<div className="fmEr">{error}</div>}</div></FI></div></section>

      <footer className="ft"><div className="container ftIn"><div className="ftTop"><div><Link href="/" className="ftBr"><div className="navLo ftLoW"><Image src="/omela-logo-mark.png" alt="Omela" width={26} height={26} style={{width:"100%",height:"100%",objectFit:"contain"}}/></div><div><div className="ftBrN">Omela</div><div className="ftBrS">POWERED BY LAURA</div></div></Link></div><div className="ftCols"><div className="ftCol"><div className="ftColT">Product</div><Link href="/demo" className="ftLk">Try Laura</Link><Link href="/how-laura-helps" className="ftLk">Use cases</Link><Link href="/quiz" className="ftLk">Health Quiz</Link><Link href="/status" className="ftLk">Status</Link></div><div className="ftCol"><div className="ftColT">Legal</div><Link href="/privacy" className="ftLk">Privacy</Link><Link href="/terms" className="ftLk">Terms</Link><a href="mailto:notice@omela.ai" className="ftLk">Contact</a></div></div></div><div className="ftDsc">Laura is a care navigation assistant, not a medical professional. She does not provide diagnosis or treatment. For emergencies, call 999 or 911.</div><div className="ftBtm"><p>&copy; 2026 Omela.</p></div></div></footer>
    </div>
  </>);
}

